import React, { useState } from 'react';
import { WordCloud } from '@isoterik/react-word-cloud';

function CloudScope({ words }) {
  const [selectedWord, setSelectedWord] = useState(null);

  const wordData = Object.entries(words).map(([text, value]) => ({ text, value }));

  if (selectedWord) {
    return (
      <div style={{ padding: '20px', textAlign: 'center' }}>
        <h2>Drill Down: {selectedWord}</h2>
        <button onClick={() => setSelectedWord(null)}>Back to Cloud</button>
      </div>
    );
  }

  return (
    <div style={{ height: '500px', width: '100%' }}>
      <WordCloud 
        words={wordData} 
        onWordClick={(word) => setSelectedWord(word.text)}
        options={{ 
          spiral: 'archimedean', // This forces the "cloud" spiral
          rotations: 2,          // Adds organic, slightly tilted look
          rotationAngles: [0, 90], 
          fontSizes: [20, 80],   // Huge range for visual impact
          colors: ['#4285F4', '#DB4437', '#F4B400', '#0F9D58'] 
        }}
      />
    </div>
  );
}

export default CloudScope;
